// Normalize incoming data by flattening nested objects, sanitizing null values, and converting timestamps to ISO format

// Helper function to flatten nested objects with dot notation
function flattenObject(obj, prefix = '') {
  let flattened = {};

  for (let key in obj) {
    if (obj.hasOwnProperty(key)) {
      const newKey = prefix ? `${prefix}.${key}` : key;

      if (obj[key] !== null && typeof obj[key] === 'object' && !Array.isArray(obj[key]) && !(obj[key] instanceof Date)) {
        Object.assign(flattened, flattenObject(obj[key], newKey));
      } else {
        flattened[newKey] = obj[key];
      }
    }
  }

  return flattened;
}

// Helper function to sanitize null/undefined values
function sanitizeValue(value) {
  if (value === null || value === undefined) {
    return '';
  }
  return value;
}

// Helper function to convert date fields to ISO format
function convertDateToISO(value) {
  if (!value) return value;

  // Check if it's already a Date object
  if (value instanceof Date) {
    return value.toISOString();
  }

  // Try to parse as date
  const date = new Date(value);
  if (!isNaN(date.getTime())) {
    return date.toISOString();
  }

  return value;
}

// Process all items
const normalizedItems = [];

for (const item of $input.all()) {
  const originalPayload = JSON.parse(JSON.stringify(item.json));

  // Flatten the object
  let flattened = flattenObject(item.json);

  // Sanitize null/undefined values and convert dates
  let normalized = {};
  for (let key in flattened) {
    let value = flattened[key];

    // Convert date fields to ISO format
    if (key.toLowerCase().includes('date') || key.toLowerCase().includes('time') || key.toLowerCase().includes('timestamp')) {
      value = convertDateToISO(value);
    }

    // Sanitize null/undefined
    normalized[key] = sanitizeValue(value);
  }

  // Add metadata fields
  normalized.source = 'webhook';
  normalized.original_payload = JSON.stringify(originalPayload);
  normalized.created_at = new Date().toISOString();

  normalizedItems.push({ json: normalized });
}

return normalizedItems;

