// Calculate retry logic with exponential backoff

// Get the error trigger data
const errorData = $input.first().json;

// Extract retry count from execution metadata or default to 0
let retryCount = 0;
if (errorData.execution && errorData.execution.retryOf) {
  // If this execution is a retry, increment the count
  retryCount = (errorData.execution.retryCount || 0) + 1;
} else {
  // First retry attempt
  retryCount = 0;
}

// Increment retry count
retryCount++;

// Calculate backoff delay with exponential backoff: 1s, 2s, 4s, 8s...
const backoffMs = Math.pow(2, retryCount) * 1000;

// Determine if we should retry (max 3 retries)
const shouldRetry = retryCount < 3;

// Extract error details
const errorDetails = {
  message: errorData.error?.message || 'Unknown error',
  stack: errorData.error?.stack || '',
  node: errorData.node?.name || 'Unknown node',
  timestamp: new Date().toISOString()
};

// Get the failed workflow ID
const failedWorkflowId = errorData.workflow?.id || $workflow.id;

// Return the retry logic object
return [{
  json: {
    retryCount: retryCount,
    backoffMs: backoffMs,
    shouldRetry: shouldRetry,
    errorDetails: errorDetails,
    failedWorkflowId: failedWorkflowId,
    maxRetries: 3
  }
}];

// Implement exponential backoff delay

// Get the backoff delay from input data
const inputData = $input.first().json;
const backoffMs = inputData.backoffMs || 1000;

// Wait for the backoff period
await new Promise(resolve => setTimeout(resolve, backoffMs));

// Return the input data unchanged after the delay completes
return $input.all();

